// ═══════════════════════════════════════════════════════
// HERO CANVAS — Animated D3 Force-Directed Background
// ═══════════════════════════════════════════════════════
(function initHeroCanvas() {
  const canvas = document.getElementById('hero-canvas');
  if (!canvas) return;
  const ctx = canvas.getContext('2d');
  let width, height, nodes = [], links = [];
  const NODE_COUNT = 50;
  const COLORS = ['#6E40C9', '#8B5CF6', '#58A6FF', '#3FB950', '#F0883E', '#F85149'];

  function resize() {
    width = canvas.parentElement.clientWidth;
    height = canvas.parentElement.clientHeight;
    canvas.width = width * devicePixelRatio;
    canvas.height = height * devicePixelRatio;
    canvas.style.width = width + 'px';
    canvas.style.height = height + 'px';
    ctx.scale(devicePixelRatio, devicePixelRatio);
  }

  function init() {
    resize();
    nodes = Array.from({ length: NODE_COUNT }, (_, i) => ({
      x: Math.random() * width,
      y: Math.random() * height,
      vx: (Math.random() - 0.5) * 0.4,
      vy: (Math.random() - 0.5) * 0.4,
      r: 2 + Math.random() * 3,
      color: COLORS[Math.floor(Math.random() * COLORS.length)],
    }));
    // Create random connections
    links = [];
    for (let i = 0; i < NODE_COUNT * 0.6; i++) {
      const a = Math.floor(Math.random() * NODE_COUNT);
      const b = Math.floor(Math.random() * NODE_COUNT);
      if (a !== b) links.push([a, b]);
    }
  }

  function animate() {
    ctx.clearRect(0, 0, width, height);
    // Draw links
    ctx.strokeStyle = 'rgba(110, 64, 201, 0.12)';
    ctx.lineWidth = 0.5;
    for (const [a, b] of links) {
      const na = nodes[a], nb = nodes[b];
      const dist = Math.hypot(na.x - nb.x, na.y - nb.y);
      if (dist < 200) {
        ctx.beginPath();
        ctx.moveTo(na.x, na.y);
        ctx.lineTo(nb.x, nb.y);
        ctx.stroke();
      }
    }
    // Draw and update nodes
    for (const n of nodes) {
      ctx.beginPath();
      ctx.arc(n.x, n.y, n.r, 0, Math.PI * 2);
      ctx.fillStyle = n.color;
      ctx.globalAlpha = 0.4;
      ctx.fill();
      ctx.globalAlpha = 1;
      n.x += n.vx;
      n.y += n.vy;
      if (n.x < 0 || n.x > width) n.vx *= -1;
      if (n.y < 0 || n.y > height) n.vy *= -1;
    }
    requestAnimationFrame(animate);
  }

  init();
  animate();
  window.addEventListener('resize', () => { resize(); });
})();

