/* ── CSS Custom Properties ──────────────────────────── */
:root {
  --base: #0D1117;
  --surface: #161B22;
  --surface-high: #1C2129;
  --surface-higher: #21262D;
  --surface-highest: #2D333B;
  --border: rgba(110, 118, 129, 0.25);
  --border-strong: rgba(110, 118, 129, 0.45);

  --primary: #6E40C9;
  --primary-light: #8B5CF6;
  --primary-dim: rgba(110, 64, 201, 0.15);

  --success: #3FB950;
  --info: #58A6FF;
  --warning: #F0883E;
  --danger: #F85149;

  --text-primary: #E6EDF3;
  --text-secondary: #8B949E;
  --text-muted: #6E7681;

  --font-sans: 'Inter', -apple-system, 'Segoe UI', sans-serif;
  --font-mono: 'JetBrains Mono', 'Fira Code', 'Consolas', monospace;

  --radius: 0.5rem;
  --radius-lg: 0.75rem;
  --radius-xl: 1rem;
}

/* ── Base ───────────────────────────────────────────── */
* { box-sizing: border-box; }
html { scroll-behavior: smooth; }
body {
  margin: 0;
  background: var(--base);
  color: var(--text-primary);
  font-family: var(--font-sans);
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

/* ── Material Icons ─────────────────────────────────── */
.material-symbols-outlined {
  font-variation-settings: 'FILL' 0, 'wght' 400, 'GRAD' 0, 'opsz' 24;
  display: inline-block;
  line-height: 1;
  text-transform: none;
  letter-spacing: normal;
  word-wrap: normal;
  white-space: nowrap;
  direction: ltr;
  font-family: 'Material Symbols Outlined';
}
.fill { font-variation-settings: 'FILL' 1, 'wght' 400, 'GRAD' 0, 'opsz' 24; }

/* ── Gradients ──────────────────────────────────────── */
.ai-gradient { background: linear-gradient(135deg, #6E40C9 0%, #8B5CF6 50%, #58A6FF 100%); }
.ai-gradient-text {
  background: linear-gradient(135deg, #8B5CF6, #58A6FF);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

/* ── Glass ──────────────────────────────────────────── */
.glass {
  background: rgba(22, 27, 34, 0.85);
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
}

/* ── Scrollbar ──────────────────────────────────────── */
.scroll { scrollbar-width: thin; scrollbar-color: var(--surface-highest) transparent; }
.scroll::-webkit-scrollbar { width: 5px; }
.scroll::-webkit-scrollbar-track { background: transparent; }
.scroll::-webkit-scrollbar-thumb { background: var(--surface-highest); border-radius: 10px; }
.scroll::-webkit-scrollbar-thumb:hover { background: var(--text-muted); }

/* ── Input Reset ────────────────────────────────────── */
input:focus, textarea:focus, select:focus { outline: none !important; box-shadow: none !important; }

/* ═══════════════════════════════════════════════════════
   Animations
   ═══════════════════════════════════════════════════════ */
@keyframes spin { to { transform: rotate(360deg); } }
@keyframes bounce { 0%,100% { transform: translateY(0); } 50% { transform: translateY(-5px); } }
@keyframes pulse { 0%,100% { opacity: 1; } 50% { opacity: 0.3; } }
@keyframes fade-in { from { opacity: 0; transform: translateY(6px); } to { opacity: 1; transform: translateY(0); } }
@keyframes fade-up { from { opacity: 0; transform: translateY(20px); } to { opacity: 1; transform: translateY(0); } }
@keyframes toast-in { from { opacity: 0; transform: translateX(80px); } to { opacity: 1; transform: translateX(0); } }
@keyframes toast-out { to { opacity: 0; transform: translateX(80px); } }
@keyframes shimmer { 0% { background-position: -200% 0; } 100% { background-position: 200% 0; } }
@keyframes glow-pulse {
  0%, 100% { box-shadow: 0 0 5px rgba(110, 64, 201, 0.2), 0 0 15px rgba(110, 64, 201, 0.1); }
  50% { box-shadow: 0 0 10px rgba(110, 64, 201, 0.4), 0 0 30px rgba(110, 64, 201, 0.15); }
}
@keyframes float {
  0%, 100% { transform: translateY(0); }
  50% { transform: translateY(-8px); }
}

.spin { animation: spin 1s linear infinite; }
.b1 { animation: bounce 1.2s ease-in-out infinite; animation-delay: 0ms; }
.b2 { animation: bounce 1.2s ease-in-out infinite; animation-delay: 180ms; }
.b3 { animation: bounce 1.2s ease-in-out infinite; animation-delay: 360ms; }
.pulse-dot { animation: pulse 2s ease-in-out infinite; }
.fade-in { animation: fade-in 0.3s ease forwards; }
.fade-up { animation: fade-up 0.5s ease forwards; }
.glow-pulse { animation: glow-pulse 3s ease-in-out infinite; }

